class Solution {
public:
    int numSub(string s) {
        const int MOD = 1e9 + 7;
        int count = 0;
        int result = 0;
        for (char c : s) {
            if (c == '1') {
                count++;
                result = (result + count) % MOD;
            } else {
                count = 0;
            }
        }
        return result;
    }
};

